// TestCapabilityAnnouncement_JSONSerialization verifies JSON roundtrip
func TestCapabilityAnnouncement_JSONSerialization(t *testing.T) {
	original := &CapabilityAnnouncement{
		InstanceName: "graph-ingest",
		Component:    "graph-ingest",
		Type:         "processor",
		Version:      "1.0.0",
		Queries: []QueryCapability{
			{
				Subject:     "graph.ingest.query.entity",
				Operation:   "getEntity",
				Description: "Get entity by ID",
			},
		},
		InputPorts: []PortCapability{
			{
				Name:        "events",
				Subject:     "events.>",
				Type:        "stream",
				Interface:   "message.Message",
				Description: "Event stream",
			},
		},
		OutputPorts: []PortCapability{
			{
				Name:    "triples",
				Subject: "graph.triples",
				Type:    "stream",
			},
		},
		Timestamp: time.Date(2024, 1, 1, 12, 0, 0, 0, time.UTC),
		TTL:       60 * time.Second,
		NodeID:    "node1",
	}

	// Marshal to JSON
	data, err := json.Marshal(original)
	if err != nil {
		t.Fatalf("Marshal failed: %v", err)
	}

	// Unmarshal back
	var decoded CapabilityAnnouncement
	if err := json.Unmarshal(data, &decoded); err != nil {
		t.Fatalf("Unmarshal failed: %v", err)
	}

	// Verify all fields
	if decoded.InstanceName != original.InstanceName {
		t.Errorf("InstanceName: got %q, want %q", decoded.InstanceName, original.InstanceName)
	}
	if decoded.Component != original.Component {
		t.Errorf("Component: got %q, want %q", decoded.Component, original.Component)
	}
	if decoded.Type != original.Type {
		t.Errorf("Type: got %q, want %q", decoded.Type, original.Type)
	}
	if decoded.Version != original.Version {
		t.Errorf("Version: got %q, want %q", decoded.Version, original.Version)
	}
	if decoded.NodeID != original.NodeID {
		t.Errorf("NodeID: got %q, want %q", decoded.NodeID, original.NodeID)
	}

	// Verify TTL (Duration serialization)
	if decoded.TTL != original.TTL {
		t.Errorf("TTL: got %v, want %v", decoded.TTL, original.TTL)
	}

	// Verify Timestamp
	if !decoded.Timestamp.Equal(original.Timestamp) {
		t.Errorf("Timestamp: got %v, want %v", decoded.Timestamp, original.Timestamp)
	}

	// Verify Queries slice
	if len(decoded.Queries) != 1 {
		t.Fatalf("Queries length: got %d, want 1", len(decoded.Queries))
	}
	if decoded.Queries[0].Subject != "graph.ingest.query.entity" {
		t.Errorf("Query subject: got %q, want %q",
			decoded.Queries[0].Subject, "graph.ingest.query.entity")
	}
	if decoded.Queries[0].Operation != "getEntity" {
		t.Errorf("Query operation: got %q, want %q",
			decoded.Queries[0].Operation, "getEntity")
	}

	// Verify InputPorts slice
	if len(decoded.InputPorts) != 1 {
		t.Fatalf("InputPorts length: got %d, want 1", len(decoded.InputPorts))
	}
	if decoded.InputPorts[0].Name != "events" {
		t.Errorf("InputPort name: got %q, want %q", decoded.InputPorts[0].Name, "events")
	}
	if decoded.InputPorts[0].Interface != "message.Message" {
		t.Errorf("InputPort interface: got %q, want %q",
			decoded.InputPorts[0].Interface, "message.Message")
	}

	// Verify OutputPorts slice
	if len(decoded.OutputPorts) != 1 {
		t.Fatalf("OutputPorts length: got %d, want 1", len(decoded.OutputPorts))
	}
	if decoded.OutputPorts[0].Subject != "graph.triples" {
		t.Errorf("OutputPort subject: got %q, want %q",
			decoded.OutputPorts[0].Subject, "graph.triples")
	}
}

