// TestPortCapability_FromPort verifies conversion from component Port to PortCapability
func TestPortCapability_FromPort(t *testing.T) {
	// This test defines expected behavior for a helper function
	// that converts component.Port to PortCapability.
	// Builder must implement this conversion logic.

	// Expected: NATSStreamPort → PortCapability
	streamPort := Port{
		Name: "events",
		Config: &NATSStreamPortConfig{
			Subject:  "events.>",
			Consumer: "test-consumer",
		},
		Description: "Event stream input",
	}

	cap := portToCapability(streamPort)

	if cap.Name != "events" {
		t.Errorf("Name: got %q, want %q", cap.Name, "events")
	}
	if cap.Subject != "events.>" {
		t.Errorf("Subject: got %q, want %q", cap.Subject, "events.>")
	}
	if cap.Type != "stream" {
		t.Errorf("Type: got %q, want %q (expected 'stream' for NATSStreamPort)", cap.Type, "stream")
	}

	// Expected: NATSRequestPort → PortCapability
	requestPort := Port{
		Name: "query",
		Config: &NATSRequestPortConfig{
			Subject: "graph.query",
		},
		Description: "Query endpoint",
	}

	cap = portToCapability(requestPort)

	if cap.Name != "query" {
		t.Errorf("Name: got %q, want %q", cap.Name, "query")
	}
	if cap.Subject != "graph.query" {
		t.Errorf("Subject: got %q, want %q", cap.Subject, "graph.query")
	}
	if cap.Type != "request" {
		t.Errorf("Type: got %q, want %q (expected 'request' for NATSRequestPort)", cap.Type, "request")
	}
}

// portToCapability is a helper that Builder must implement.
// This test defines the expected behavior.
func portToCapability(p Port) PortCapability {
	cap := PortCapability{
		Name:        p.Name,
		Description: p.Description,
	}

	// Extract subject and type based on port config type
	switch cfg := p.Config.(type) {
	case *NATSStreamPortConfig:
		cap.Subject = cfg.Subject
		cap.Type = "stream"
	case *NATSRequestPortConfig:
		cap.Subject = cfg.Subject
		cap.Type = "request"
	case nil:
		// Port with no config - use empty values
		cap.Subject = ""
		cap.Type = "unknown"
	default:
		// Unknown port config type
		cap.Subject = ""
		cap.Type = "unknown"
	}

	return cap
}

